  "protocol_type": "amm",
  "invariants": [
    {
      "property": "x * y = k (constant product) must hold after every swap",
      "critical": true
    },
    {
      "property": "LP shares = sqrt(dx * dy) for initial deposit",
      "critical": true
    },
    {
      "property": "Fee accumulates in reserves, not distributed separately",
      "critical": true
    },
    {
      "property": "Slippage protection: actual output >= minAmountOut",
      "critical": true
    }
  ],
  "attack_surfaces": [
    "Oracle manipulation via reserve ratio",
    "Sandwich attacks",
    "LP token inflation",
    "Impermanent loss exploitation"
  ]
}

