        );
        require(
            StakingRewardsLike(p.rewards).owner() == chainlog.getAddress("MCD_PAUSE_PROXY"),
            "Usds01PreFarmingInit/invalid-owner"
        );

        chainlog.setAddress(p.rewardsKey, p.rewards);
    }
}

