struct UsdsSkyFarmingInitParams {
    address usds;
    address sky;
    address rewards;
    bytes32 rewardsKey; // Chainlog key
    address dist;
    bytes32 distKey; // Chainlog key
    address vest;
    uint256 vestTot;
    uint256 vestBgn;
    uint256 vestTau;
}

struct UsdsSkyFarmingInitResult {
    uint256 vestId;
}

