            skip(timeSkip);
            k.dist.distribute();
            balances[i] = k.rewardsToken.balanceOf(address(k.rewards));
        }

        uint256[] memory deltas = new uint256[](totalDistributions - 1);
        for (uint256 i = 1; i < totalDistributions; i++) {
            deltas[i - 1] = balances[i] - balances[i - 1];
