        vm.startPrank(owner);
        _;
        vm.stopPrank();
    }

    modifier callAsPauseProxy() {
        vm.startPrank(pauseProxy);
        _;
        vm.stopPrank();
    }

    constructor(
        Vm vm_,
        address engine_,
        address owner_,
        uint256 index_,
        address spot_,
        address dog_,
        address pauseProxy_,
        address[] memory voteDelegates_,
        address[] memory farms_
    ) {
